import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const n="/docs/images/smartContactMic.jpg",u=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md"}'),i={name:"getting-started/index.md"};function s(h,t,p,d,l,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>The Soniphorm Smart Contact Mic (SCM) is a contact microphone with a programmable DSP engine built into the board. Clip it to a wine glass, a spring, a radiator, a window, or your own body, and it listens to vibrations the way any contact mic does. The difference is what happens next: the signal is fed into a patch you design visually in a browser-based patcher, and from there it can drive anything. Every tap can trigger an oscillator, a drum machine, a sampler, or a MIDI note to an external synth. Every sound can be looped, sliced, granulated, resampled, or sequenced in time with the rest of the patch. No code, no Arduino, no laptop once the patch is loaded.</p><p>Because the SCM is reprogrammable, one device can be many things. Swap the patch and the same board becomes a sensitive instrument pickup, a field recorder, an improvised looper, a step sequencer driven by real-world taps, a MIDI trigger for a DAW, a granular sketchpad, or any combination of those at once. The whole rig fits in a pocket: plug the SCM into an Android phone over USB-C to power it, control it over Bluetooth, and you&#39;ve got a portable instrument built from whatever&#39;s around you.</p><img src="'+n+'" alt="Soniphorm Smart Contact Mic"><p>This section walks you through everything you need to go from unboxing to hearing your first sound.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li><p><strong><a href="./flashing-firmware.html">Update firmware (if prompted)</a></strong> -- Your SCM ships with firmware already installed, so you can skip this step unless the patcher prompts you that a newer version is available. If it does, follow the link to update in-browser (no software to install).</p></li><li><p><strong><a href="/docs/getting-started/connecting.html">Connect to the patcher</a></strong> -- Open the web patcher and connect to your board over USB.</p></li><li><p><strong><a href="/docs/getting-started/first-patch.html">Build your first patch</a></strong> -- Create a simple oscillator-to-output patch and hear it play.</p></li><li><p><strong><a href="/docs/getting-started/hardware.html">Learn the hardware</a></strong> -- Understand the pots, buttons, encoder, and banking system.</p></li></ol><h2 id="what-you-need" tabindex="-1">What You Need <a class="header-anchor" href="#what-you-need" aria-label="Permalink to &quot;What You Need&quot;">​</a></h2><ul><li>A Soniphorm Smart Contact Mic board</li><li>A USB-C cable (data-capable, not charge-only)</li><li>A computer with Chrome or Edge (Web Serial requires a Chromium browser)</li><li>Headphones or speakers connected to the audio output</li></ul><h2 id="support-community" tabindex="-1">Support &amp; Community <a class="header-anchor" href="#support-community" aria-label="Permalink to &quot;Support &amp; Community&quot;">​</a></h2><ul><li><strong>Discord:</strong> <a href="https://discord.gg/yAFWg4eQXQ" target="_blank" rel="noreferrer">Join the Soniphorm Discord</a> for discussion, technical support, and to connect with other SCM users.</li><li><strong>Patcher app:</strong> <a href="https://soniphorm.com/patcher" target="_blank" rel="noreferrer">soniphorm.com/patcher</a> is the browser-based app for programming your Smart Contact Mic.</li></ul>',11)])])}const g=e(i,[["render",s]]);export{u as __pageData,g as default};
